# Real Estate Quality
# ---------------------------------------------------------------------------
_add("quality_score", "Real Estate Quality Score", "Composite quality score (0-100).", "Evaluates portfolio quality, financial position, management, occupancy, tenant mix, lease duration, and distribution safety. >70 = high quality; <30 = weak.", "Weighted sum of: portfolio quality + occupancy + leverage + distribution coverage + management + diversification", "real_estate_quality")
_add("management_quality", "Management Quality Assessment", "Qualitative read on the management team's track record.", "Track record of accretive capital deployment, dividend growth history, and alignment through ownership. Externally managed structures deserve extra scrutiny.", "Qualitative evaluation of capital allocation and track record", "real_estate_quality")
_add("jurisdiction_assessment", "Jurisdiction Risk Assessment", "Property-market risk by country/region.", "Tier 1 (US, UK, Western Europe, developed Asia) offers deep capital markets and transparent property rights. Tier 3 elevates political and currency risk on rents.", "Tier classification + country-level commentary", "real_estate_quality")
_add("portfolio_quality", "Portfolio Quality", "Quality of the underlying real estate assets.", "Evaluates property class (A/B/C), age, location, and market share within submarkets. Class A in primary markets commands premium cap rates and tenant demand.", "Qualitative assessment of asset class, vintage, and market position", "real_estate_quality")
_add("portfolio_diversification", "Portfolio Diversification", "Diversification across tenants, geographies, and property types.", "Reduces single-tenant and regional risk. Quality REITs limit top-10 tenant exposure to <30% and avoid single-market concentration >20%.", "Concentration scoring by tenant, geography, and asset type", "real_estate_quality")
_add("occupancy_assessment", "Occupancy Assessment", "Qualitative assessment of current and trending occupancy.", "Occupancy level + direction = operational health signal. Rising occupancy in a stable portfolio is the cleanest positive indicator.", "Occupancy level + trend classification", "real_estate_quality")
_add("lease_duration_assessment", "Lease Duration (WALT) Assessment", "Weighted average lease term across the portfolio.", "Longer WALT = higher cash-flow visibility. Net-lease REITs target 10+ years; apartment REITs run 1-year leases. Assess WALT against property-type norms.", "WALT = Sum(Remaining Term * Annual Rent) / Total Annual Rent", "real_estate_quality")
_add("tenant_concentration", "Tenant Concentration", "Concentration risk in top tenants.", "Top-10 tenants ideally <30%; single-tenant exposure above 10% is a risk factor. Credit rating of top tenants matters for distribution safety.", "Top-N Tenant % = Rent from Top-N / Total Rent", "real_estate_quality")
_add("same_store_noi_trend", "Same-Store NOI Trend", "Multi-year trend in same-store NOI growth.", "Consistent positive SS NOI growth confirms pricing power and operational execution. Sustained negative trends are a yellow flag for the asset class or management.", "Multi-year SS NOI growth trajectory", "real_estate_quality")
_add("cap_rate_assessment", "Cap Rate Assessment", "Implied cap rate vs private-market transaction cap rates.", "Implied cap > private market = stock cheap vs NAV. Implied cap < private market = public premium (often justified by platform value or growth).", "Implied Cap Rate vs Private Market Cap Rates", "real_estate_quality")
_add("financial_position", "Financial Position", "Overall balance-sheet strength.", "Evaluates leverage, debt maturity ladder, rate exposure, liquidity, and credit rating. Investment-grade REITs access capital on better terms through cycles.", "Composite of leverage + coverage + maturity + rating", "real_estate_quality")
_add("dilution_risk", "Dilution Risk", "Risk from future share issuance.", "REITs habitually issue equity. Dilution is acceptable when new capital earns above the cost of capital — issuance below NAV destroys value.", "Historical dilution pace + pipeline funding needs", "real_estate_quality")
_add("catalyst_density", "Catalyst Density", "Frequency of near-term value-creation catalysts.", "Development deliveries, redevelopment, lease-up, and accretive acquisitions drive FFO/share growth. High catalyst density supports multiple expansion.", "Count and quality of announced catalysts in next 12-18 months", "real_estate_quality")
_add("strategic_backing", "Strategic Backing", "Support from strategic partners, sponsors, or parent companies.", "External sponsorship provides deal flow and capital access. Joint ventures with institutional partners signal asset quality.", "Qualitative assessment of sponsor/partner ecosystem", "real_estate_quality")
_add("competitive_position", "Competitive Position", "Market position within the property sub-sector.", "Scale advantages in REITs show up as lower G&A per property, better tenant relationships, and preferred access to acquisition pipelines.", "Market share + scale + barriers-to-entry assessment", "real_estate_quality")
_add("asset_backing", "Asset Backing", "Value of tangible real estate vs market cap.", "Hard-asset backing differentiates REITs from other equities. A discount to replacement cost offers a margin of safety in down cycles.", "Qualitative: gross real estate value vs market cap", "real_estate_quality")
_add("niche_position", "Niche Position", "Position in a specialized property niche.", "Specialty REITs (data centers, cell towers, life sciences) often enjoy structural demand tailwinds and higher multiples than diversified peers.", "Qualitative read on niche demand drivers", "real_estate_quality")
_add("insider_alignment", "Insider Alignment", "Degree of insider ownership and skin in the game.", "Founder-led REITs with significant insider stakes tend to allocate capital more conservatively. Externally managed REITs often show structural misalignment.", "Insider ownership % + alignment mechanisms", "real_estate_quality")
_add("revenue_predictability", "Revenue Predictability", "Stability and visibility of rental revenue.", "Long WALT, staggered expirations, and high-credit tenants create predictable revenue. Net-lease REITs have the most predictable revenue streams.", "WALT + tenant credit + lease structure assessment", "real_estate_quality")

