_add("net_insider_shares_3m", "Net Insider Buys (3M)", "Net shares bought by insiders over the trailing 3 months.", "Insider buying at REITs is a strong positive signal since insiders understand NAV better than outsiders. Positive net buys near 52-week lows is particularly bullish.", "Net Insider Shares = Buys - Sells (last 90 days)", "market_intelligence")
_add("insider_buy_signal", "Insider Buy Signal", "Qualitative flag on recent insider activity.", "Clustered insider purchases by multiple executives often precede NAV revisions or accretive acquisitions.", "Signal derived from size + breadth + timing of purchases", "market_intelligence")
_add("institutions_pct", "Institutional Ownership %", "Percentage held by institutional investors.", "REITs typically show 60-90% institutional ownership. Meaningful changes flag index rebalancing or conviction shifts among REIT-focused funds.", "Institutional % = Institutional Shares / Shares Outstanding", "market_intelligence")
_add("analyst_count", "Analyst Count", "Number of sell-side analysts covering the stock.", "Low coverage (<5) can mean inefficient pricing opportunities in small/mid-cap REITs. High coverage signals institutional relevance.", "Count of distinct analysts with active ratings", "market_intelligence")
_add("recommendation", "Analyst Recommendation", "Consensus analyst recommendation.", "Useful as a sentiment gauge only. Analyst downgrades often lag NAV discounts, so insider buying + price discount tends to be a stronger signal.", "Consensus rating (Buy/Hold/Sell)", "market_intelligence")
_add("target_mean", "Mean Price Target", "Average 12-month analyst price target.", "Compare to NAV per share. When the target is below NAV, analysts see execution risk; when above NAV, they see platform/growth value.", "Mean of all analyst targets", "market_intelligence")
_add("target_upside_pct", "Price Target Upside (%)", "Upside to the consensus price target.", "Reference only; NAV-based margin of safety is a stronger anchor for REITs.", "Upside = (Target Mean - Current Price) / Current Price", "market_intelligence")
_add("short_pct_of_float", "Short Interest (% of Float)", "Short interest as a percentage of float.", "REITs can attract shorts when leverage is high, refinancing walls loom, or property-type sentiment turns. >10% short is elevated.", "Short % = Shares Short / Float", "market_intelligence")
_add("short_squeeze_risk", "Short Squeeze Risk", "Qualitative flag on short-squeeze potential.", "High short interest plus low float plus a positive NAV catalyst can trigger squeezes. Rare but meaningful for small-cap REITs.", "Derived from short % + float + days-to-cover", "market_intelligence")
_add("price_current", "Current Price", "Latest market price.", "Input for all valuation ratios and margin-of-safety calculations.", "Current Price = Latest Close", "market_intelligence")
_add("price_52w_high", "52-Week High", "Highest price over the trailing 52 weeks.", "Reference for momentum; distance from highs indicates where the market is in the REIT cycle.", "Max(Daily Close, last 252 trading days)", "market_intelligence")
_add("price_52w_low", "52-Week Low", "Lowest price over the trailing 52 weeks.", "Near the 52-week low with supportive NAV can indicate an entry point; confirm with insider activity and coverage.", "Min(Daily Close, last 252 trading days)", "market_intelligence")
_add("pct_from_52w_high", "% from 52-Week High", "Percentage below the 52-week high.", ">20% below highs often coincides with REIT-cycle lows — check the NAV discount and dividend safety.", "% = (Current - 52W High) / 52W High", "market_intelligence")
_add("price_52w_range_position", "52-Week Range Position", "Current price position within the 52-week range (0-100%).", "Values near 0 indicate compressed valuations; near 100 indicate momentum/premium.", "Position = (Price - 52W Low) / (52W High - 52W Low)", "market_intelligence")
_add("sma_50", "50-Day Simple Moving Average", "Average closing price over the last 50 trading days.", "Short-term trend marker. Price above the 50-SMA signals positive short-term momentum.", "SMA_50 = Avg(Close, last 50 days)", "market_intelligence")
_add("sma_200", "200-Day Simple Moving Average", "Average closing price over the last 200 trading days.", "Long-term trend marker. Price above the 200-SMA confirms a long-term uptrend.", "SMA_200 = Avg(Close, last 200 days)", "market_intelligence")
_add("above_sma_50", "Above 50-SMA?", "Whether price is above the 50-day moving average.", "Short-term trend confirmation. Combine with volume and fundamentals rather than trading off alone.", "Boolean: Current Price > SMA_50", "market_intelligence")
_add("above_sma_200", "Above 200-SMA?", "Whether price is above the 200-day moving average.", "Long-term trend confirmation. Below 200-SMA during a rate-up cycle is common for rate-sensitive REITs.", "Boolean: Current Price > SMA_200", "market_intelligence")
_add("golden_cross", "Golden Cross", "Whether the 50-SMA has crossed above the 200-SMA.", "Technical trend signal. REIT golden crosses often follow rate-cut cycles as yield-sensitive flows return.", "Boolean: SMA_50 > SMA_200 (recent cross)", "market_intelligence")
_add("beta", "Beta", "Volatility relative to the broader market.", "REITs typically run beta 0.7-1.0. Rising-rate episodes temporarily elevate beta as REITs are repriced as bond proxies.", "Beta = Cov(Stock, Market) / Var(Market)", "market_intelligence")
_add("volume_trend", "Volume Trend", "Trend in trading volume.", "Rising volume on advances confirms strength; rising volume on declines confirms distribution. REITs see volume spikes around quarterly NOI prints.", "Current Volume vs 10-day/30-day averages", "market_intelligence")
_add("projected_dilution_annual_pct", "Projected Annual Dilution %", "Forecast annual share issuance from ATM programs and development funding.", "REITs often run at-the-market offerings. 2-4%/yr is normal for externally-growing REITs; issuance below NAV is value-destructive.", "Projected % = (Projected New Shares) / Current Shares", "market_intelligence")
_add("financing_warning", "Financing Warning", "Flag on near-term financing needs.", "REITs with large maturity walls + high leverage + depressed share prices may be forced into dilutive offerings or asset sales.", "Flag derived from maturity ladder + liquidity + market conditions", "market_intelligence")
_add("benchmark_rate_name", "Benchmark Rate (Name)", "Name of the relevant benchmark interest rate (e.g., 10Y US Treasury).", "REITs are highly rate-sensitive. The 10-year Treasury is the most relevant benchmark for REIT discount rates and dividend-yield comparison.", "Identifier of the tracked benchmark rate", "market_intelligence")
_add("benchmark_rate_value", "Benchmark Rate (Value)", "Current value of the benchmark interest rate.", "Compare dividend yield to the 10-year yield for relative attractiveness. Rising benchmarks pressure REIT multiples; falling benchmarks support them.", "Current Rate (%)", "market_intelligence")
_add("sector_etf_name", "Sector ETF Name", "Name of the relevant sector ETF (e.g., VNQ).", "Sector-ETF performance serves as a REIT-cycle proxy. Under/outperformance vs the ETF isolates company-specific alpha.", "Name of relevant real-estate sector ETF", "market_intelligence")
_add("sector_etf_ticker", "Sector ETF Ticker", "Ticker of the relevant sector ETF (e.g., VNQ, IYR).", "Used for relative-performance benchmarking and peer context.", "Ticker of relevant real-estate sector ETF", "market_intelligence")


